import json
with open('/mnt/d/ClaudeProjects/NOLAN/projects/venezuela/scene_plan.json') as f:
    data = json.load(f)

# Verify structure
print('Sections:', list(data['sections'].keys()))
total_scenes = 0
total_duration = 0
prev_visual = None
consec = 0
all_ids = []

for sec_name, scenes in data['sections'].items():
    sec_total = 0
    for s in scenes:
        all_ids.append(s['id'])
        dur = int(s['duration'].rstrip('s'))
        sec_total += dur
        total_duration += dur
        # variety check
        vt = s['visual_type']
        if vt == prev_visual:
            consec += 1
        else:
            consec = 1
        if consec > 2:
            print(f'  VIOLATION at {s[\"id\"]}: 3+ consecutive {vt}')
        prev_visual = vt
    total_scenes += len(scenes)
    print(f'  {sec_name}: {len(scenes)} scenes, {sec_total}s')

print(f'TOTAL: {total_scenes} scenes, {total_duration}s')
print(f'IDs unique: {len(set(all_ids)) == len(all_ids)}')

# Visual type distribution
from collections import Counter
vt_counts = Counter()
for sec in data['sections'].values():
    for s in sec:
        vt_counts[s['visual_type']] += 1
for vt, n in vt_counts.most_common():
    print(f'  {vt}: {n} ({100*n/total_scenes:.1f}%)')

# field discipline check
errors = []
for sec in data['sections'].values():
    for s in sec:
        if s['visual_type'] == 'b-roll':
            if not s['search_query']:
                errors.append(f'{s[\"id\"]}: b-roll missing search_query')
            if s['comfyui_prompt']:
                errors.append(f'{s[\"id\"]}: b-roll has comfyui_prompt')
        elif s['visual_type'] == 'generated-image':
            if not s['comfyui_prompt']:
                errors.append(f'{s[\"id\"]}: generated-image missing comfyui_prompt')
            if s['search_query']:
                errors.append(f'{s[\"id\"]}: generated-image has search_query')
        else:  # text-overlay or graphic
            if s['search_query'] or s['comfyui_prompt']:
                errors.append(f'{s[\"id\"]}: {s[\"visual_type\"]} should not have search_query/comfyui_prompt')
if errors:
    print('FIELD ERRORS:')
    for e in errors:
        print('  ', e)
else:
    print('Field discipline: OK')
"

